final:
module RefModule(
    input CLK,
    input RESET,
    input DIR,
    output reg [2:0] Q
);reg [2:0] obf_Q_reg;
reg [2:0] Q_next;

always @(posedge CLK) begin
    if(RESET) begin
        obf_Q_reg <= 3'b000;
    end else begin
        obf_Q_reg <= Q_next;
    end
end

always @(*) begin
    if(DIR == 1'b0) begin
        Q_next = obf_Q_reg + 3'b001;
    end else begin
        Q_next = obf_Q_reg - 3'b001;
    end
end

assign Q = obf_Q_reg;

endmodule
